def percent_covered(self, src_path):

        diff_violations = self._diff_violations().get(src_path)

        if diff_violations is None:
            return None

        # Protect against a divide by zero
        num_measured = len(diff_violations.measured_lines)
        if num_measured > 0:
            num_uncovered = len(diff_violations.lines)
            return 100 - float(num_uncovered) / num_measured * 100

        else:
            return None

def process_link(self, env, refnode, has_explicit_title, title, target):

        result = super(DotNetXRefRole, self).process_link(env, refnode,
                                                          has_explicit_title,
                                                          title, target)
        (title, target) = result
        if not has_explicit_title:
            # If the first character is a tilde, don't display the parent name
            title = title.lstrip('.')
            target = target.lstrip('~')
            if title[0:1] == '~':
                title = title[1:]
                dot = title.rfind('.')
                if dot != -1:
                    title = title[dot + 1:]
        else:
            if title != target:
                target = title = '{title}<{target}>'.format(title=title,
                                                            target=target)
        return title, target

