def parse_fn_docstring(fn):

    doc = fn.__doc__
    params, return_ = {}, {}
    param_order = []
    for line in doc.split("\n"):
        line = line.strip()
        if line.startswith(":param"):
            _, name, desc = line.split(":", 2)
            name = name[6:].strip()  # skip 'param '
            params[name] = {'desc': desc.strip()}
            param_order.append(name)
        elif line.startswith(":type"):
            _, name, desc = line.split(":", 2)
            name = name[5:].strip()  # skip 'type '
            if not name in params:
                raise ValueError("'type' without 'param' for {}".format(name))
            params[name]['type'] = desc.strip()
        elif line.startswith(":return"):
            _1, _2, desc = line.split(":", 2)
            return_['desc'] = desc
        elif line.startswith(":rtype"):
            _1, _2, desc = line.split(":", 2)
            return_['type'] = desc.strip()
    return params

def _argspec(func):

    assert isinstance(func, collections.Callable), 'Argument must be a callable'

    try: sp =  inspect.getargspec(func) if six.PY2 else inspect.getfullargspec(func)
    except TypeError:
        # inspect.getargspec() fails for built-in functions
        return []

    # Collect arguments with defaults
    ret = []
    defaults_start = len(sp.args) - len(sp.defaults) if sp.defaults else len(sp.args)
    for i, name in enumerate(sp.args):
        arg = data.ArgumentSpec(name)
        if i >= defaults_start:
            arg['default'] = sp.defaults[i - defaults_start]
        ret.append(arg)

    # *args, **kwargs
    if sp.varargs:
        ret.append(data.ArgumentSpec(sp.varargs, varargs=True))
    if six.PY2:
        if sp.keywords:
            ret.append(data.ArgumentSpec(sp.keywords, keywords=True))
    else:
        if sp.varkw:
            ret.append(data.ArgumentSpec(sp.varkw, keywords=True))

    # TODO: support Python 3: kwonlyargs, kwonlydefaults, annotations

    # Finish
    return ret

def import_path(path):
      # noqa
    sys.path.insert(0, ".")
    parts = path.split(".")
    module = None

    # Import the module as deeply as possible.  Prioritize an attribute chain
    # over a module chain
    for i in range(1, len(parts)+1):
        if module is not None and hasattr(module, parts[i-1]):
            try:
                return _import_attributes(module, parts[i-1:])
            except AttributeError:
                pass
        module_path = ".".join(parts[0:i])
        module = importlib.import_module(module_path)

    return module

